#!/usr/bin/env bash
# Seeds the local MinIO bucket with a realistic tree for browse-UI testing.
# Usage: scripts/seed-demo.sh   (MinIO + createbucket must have run)
#
# Fixtures use REAL file formats (not random bytes) so the app's previews and
# thumbnails (images via canvas, PDFs via pdf.js, text inline) actually render
# something during a demo instead of failing to decode garbage:
#   - photos/**/*.jpg, photos/2026/other.png: small real JPEG/PNG images
#     (generated once with ImageMagick, embedded below as base64 so this
#     script has no build-time tool dependency).
#   - docs/itinerary.pdf: a hand-written, valid 2-page PDF (plain text
#     content streams, no embedded fonts/images) -- pdf.js renders page 1 for
#     the thumbnail and both pages in the lightbox.
#   - docs/notes.txt, readme.md: real prose, so the inline text preview shows
#     something legible rather than binary noise.
#   - videos/clip.mp4: still opaque placeholder bytes. The app has no video
#     preview/thumbnail path (spec section 9 covers images and PDFs only), so
#     a non-decodable "video" has no effect on demo quality; producing a real
#     MP4 would need ffmpeg, which isn't assumed to be installed.
set -euo pipefail

tmp="$(mktemp -d)"
trap 'rm -rf "$tmp"' EXIT

put_file() { # path  (reads raw bytes from stdin)
  mkdir -p "$tmp/$(dirname "$1")"
  cat > "$tmp/$1"
}

put_b64() { # path  base64
  mkdir -p "$tmp/$(dirname "$1")"
  printf '%s' "$2" | base64 -d > "$tmp/$1"
}

make_random() { # path bytes
  mkdir -p "$tmp/$(dirname "$1")"
  head -c "$2" /dev/urandom > "$tmp/$1"
}

# --- real JPEG/PNG photos (ImageMagick gradients + noise, few KB each) -----
IMG_0142_B64=''
IMG_0143_B64=''
ARCHIVE_B64=''
OTHER_PNG_B64=''
ITINERARY_PDF_B64=''

put_b64 "photos/2026/trip/IMG_0142.jpg" "$IMG_0142_B64"
put_b64 "photos/2026/trip/IMG_0143.jpg" "$IMG_0143_B64"
put_b64 "photos/2026/other.png"         "$OTHER_PNG_B64"
put_b64 "photos/2025/archive.jpg"       "$ARCHIVE_B64"
put_b64 "docs/itinerary.pdf"            "$ITINERARY_PDF_B64"

# --- real text content ------------------------------------------------------
put_file "docs/notes.txt" <<'EOF'
Trip notes

- Photos are organized under photos/<year>/... -- browse by folder, or use
  search to find a file by name across the whole tree.
- This bucket was populated by scripts/seed-demo.sh for local development;
  the manifest rebuilds automatically the first time the app connects.
- Text and Markdown files preview inline (first 256 KiB); anything past
  that is truncated with a "download the full file" notice.
EOF

put_file "readme.md" <<'EOF'
# Trip Archive

Sample bucket seeded by `scripts/seed-demo.sh` for local Bare Bucket
development. It exists so the browse UI, thumbnails, and previews have
something realistic to render without needing a live user's own bucket.

## Contents

- `photos/` -- a handful of real JPEG/PNG images across two years
- `docs/` -- a real two-page PDF (`itinerary.pdf`) plus this readme
- `videos/` -- a placeholder clip (opaque bytes; the app has no video
  preview path, so this is fine)

Open the app, connect to this bucket, and hit **Refresh** (or reconnect)
if the manifest doesn't pick up these files immediately.
EOF

# --- placeholder video (no preview path exists for it; see header note) ---
make_random "videos/clip.mp4" 900000

docker run --rm --network host -v "$tmp":/seed:z --entrypoint sh minio/mc@sha256:a7fe349ef4bd8521fb8497f55c6042871b2ae640607cf99d9bede5e9bdf11727 -c '
  mc alias set local http://127.0.0.1:9000 baretest baretest123 &&
  mc cp --recursive /seed/ local/bare-bucket-it/
'
echo "Seeded. Open the app and hit Refresh (or reconnect) to rebuild the manifest."
